'use client';

import { useState } from 'react';

export default function ReportarPage() {
  const [formData, setFormData] = useState({
    nombre: '',
    cedula: '',
    telefono: '',
    ciudad: '',
    tipo_problema: '',
    descripcion: '',
  });

  const [mensaje, setMensaje] = useState('');
  const [cargando, setCargando] = useState(false);

  const handleChange = (
    e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>
  ) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setCargando(true);
    setMensaje('');

    try {
      const token = localStorage.getItem('token');

      const response = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/api/reports`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify(formData),
      });

      const data = await response.json();

      if (response.ok) {
        setMensaje('Reporte enviado correctamente');
        setFormData({
          nombre: '',
          cedula: '',
          telefono: '',
          ciudad: '',
          tipo_problema: '',
          descripcion: '',
        });
      } else {
        setMensaje(data.message || 'Error al enviar reporte');
      }
    } catch {
      setMensaje('Error al conectar con el servidor');
    } finally {
      setCargando(false);
    }
  };

  return (
    <div className="min-h-screen bg-gray-100 p-8">
      <div className="max-w-xl mx-auto bg-white p-6 rounded-lg shadow-md">
        <h1 className="text-3xl font-bold mb-6 text-center">Reportar Inquilino</h1>

        <form onSubmit={handleSubmit} className="space-y-4">
          <input
            name="nombre"
            value={formData.nombre}
            onChange={handleChange}
            placeholder="Nombre completo"
            className="w-full px-3 py-2 border rounded-lg"
            required
          />

          <input
            name="cedula"
            value={formData.cedula}
            onChange={handleChange}
            placeholder="Cédula"
            className="w-full px-3 py-2 border rounded-lg"
            required
          />

          <input
            name="telefono"
            value={formData.telefono}
            onChange={handleChange}
            placeholder="Teléfono (opcional)"
            className="w-full px-3 py-2 border rounded-lg"
          />

          <input
            name="ciudad"
            value={formData.ciudad}
            onChange={handleChange}
            placeholder="Ciudad"
            className="w-full px-3 py-2 border rounded-lg"
            required
          />

          <select
            name="tipo_problema"
            value={formData.tipo_problema}
            onChange={handleChange}
            className="w-full px-3 py-2 border rounded-lg"
            required
          >
            <option value="">Seleccione tipo de problema</option>
            <option value="mora">Mora</option>
            <option value="daños">Daños al inmueble</option>
            <option value="incumplimiento">Incumplimiento</option>
            <option value="otro">Otro</option>
          </select>

          <textarea
            name="descripcion"
            value={formData.descripcion}
            onChange={handleChange}
            placeholder="Descripción del problema"
            className="w-full px-3 py-2 border rounded-lg"
            rows={4}
            required
          />

          <button
            type="submit"
            disabled={cargando}
            className="w-full bg-blue-600 text-white py-2 rounded-lg"
          >
            {cargando ? 'Enviando...' : 'Enviar reporte'}
          </button>
        </form>

        {mensaje && (
          <p className="mt-4 text-center text-sm">{mensaje}</p>
        )}
      </div>
    </div>
  );
}